// Parse positions from loaded file
let positions = {};
try {
  const binaryData = $input.first().binary?.data?.data;
  if (binaryData) {
    const parsed = JSON.parse(Buffer.from(binaryData, 'base64').toString('utf-8'));
    positions = parsed.positions || {};
  }
} catch (e) {
  // Fallback: empty positions
  positions = {};
}

const watchlist = {
  stocks: ['NVDA', 'MSFT', 'GOOGL', 'AAPL', 'VOO'],
  crypto: ['ethereum', 'solana']
};

const now = new Date();
const hour = now.getHours();
// Morning fires at 6 AM PDT, Afternoon at 1 PM PDT
const timeLabel = hour < 10 ? 'morning' : 'afternoon';

return [{
  json: {
    positions,
    watchlist,
    timeLabel,
    isReport: true,
    source: 'Trading Monitor'
  }
}];

const input = $input.first().json;
const signals = input.signals || [];
const stocks = input.stocks || [];
const crypto = input.crypto || [];
const positions = input.positions || {};
const timeLabel = $('Prepare Input').first().json.timeLabel;

const lines = [];
const now = new Date();
lines.push(`# Trading Report — ${now.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}`);
lines.push(`\n**Session:** ${timeLabel.toUpperCase()} (${now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })})`);

lines.push('\n## Market Overview');
lines.push(input.market_overview || 'Market analysis pending.');

if (Object.keys(positions).length > 0) {
  lines.push('\n## Positions');
  for (const [id, pos] of Object.entries(positions)) {
    const data = stocks.find(s => s.symbol?.toLowerCase() === pos.symbol?.toLowerCase()) ||
                 crypto.find(c => c.id?.toLowerCase() === pos.symbol?.toLowerCase());
    const price = data?.current_price || 'N/A';
    const pnl = data ? ((data.current_price - pos.entry_price) / pos.entry_price * 100).toFixed(2) : 0;
    lines.push(`\n**${pos.symbol}**`);
    lines.push(`- Entry: $${pos.entry_price} | Current: $${price} | P&L: ${pnl >= 0 ? '+' : ''}${pnl}%`);
    lines.push(`- Stop: $${pos.stop_loss} | Target: $${pos.take_profit}`);
    if (data) lines.push(`- RSI: ${data.rsi_14 || data.rsi_14_approx || 'N/A'}`);
  }
}

lines.push('\n## Watchlist Analysis');
if (stocks.length > 0) {
  lines.push('\n**Stocks:**');
  stocks.forEach(s => {
    const sig = signals.find(sig => sig.symbol === s.symbol);
    const confidence = sig ? ` [${sig.confidence}/100]` : '';
    const action = sig ? ` — ${sig.action.toUpperCase()}` : '';
    lines.push(`- ${s.symbol}: $${s.current_price} (${s.week_change_pct > 0 ? '+' : ''}${s.week_change_pct}%)${confidence}${action}`);
    lines.push(`  RSI: ${s.rsi_14} | Vol: ${s.volume_ratio}x`);
  });
}
if (crypto.length > 0) {
  lines.push('\n**Crypto:**');
  crypto.forEach(c => {
    const sig = signals.find(sig => sig.symbol === c.symbol || sig.id === c.id);
    const confidence = sig ? ` [${sig.confidence}/100]` : '';
    const action = sig ? ` — ${sig.action.toUpperCase()}` : '';
    lines.push(`- ${c.symbol}: $${c.current_price} (${c.week_change_pct > 0 ? '+' : ''}${c.week_change_pct}%)${confidence}${action}`);
  });
}

lines.push('\n## Top Signals');
const topSignals = signals.slice(0, 5);
if (topSignals.length > 0) {
  topSignals.forEach((s, i) => {
    const urgencyEmoji = s.urgency === 'critical' ? '!!!' : s.urgency === 'high' ? '!!' : '!';
    lines.push(`${i + 1}. ${urgencyEmoji} **${s.symbol}**: ${s.action.toUpperCase()} (${s.confidence}/100)`);
    lines.push(`   ${s.reason}`);
    if (s.tech_reasons?.length) lines.push(`   _Tech: ${s.tech_reasons.join(', ')}_`);
  });
} else {
  lines.push('No significant signals at this time.');
}

lines.push('\n## Recommendations');
lines.push(input.recommendations || 'No specific recommendations at this time.');

lines.push('\n## Risk Assessment');
lines.push(input.risk_assessment || 'Market conditions normal.');

return [{
  json: {
    reportContent: lines.join('\n'),
    marketOverview: input.market_overview,
    signals,
    stocks,
    crypto,
    positions,
    timeLabel,
    timestamp: now.toISOString()
  }
}];

// Convert text to binary for file writing
const input = $('Build Report').first().json;
const reportContent = input.reportContent;

// Create binary data (base64 encoded)
const binaryData = Buffer.from(reportContent).toString('base64');

return [{
  json: input,
  binary: {
    data: {
      data: binaryData,
      mimeType: 'text/markdown',
      fileName: new Date().toISOString().split('T')[0] + '.md',
      fileExtension: 'md'
    }
  }
}];

const input = $('Build Report').first().json;
const stocks = input.stocks || [];
const crypto = input.crypto || [];
const signals = input.signals || [];

const lines = [];
lines.push('<!DOCTYPE html><html><head><style>');
lines.push('body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #1a1a2e; color: #eee; padding: 20px; }');
lines.push('.container { max-width: 600px; margin: 0 auto; }');
lines.push('.header { text-align: center; margin-bottom: 24px; }');
lines.push('.header h1 { color: #4ade80; margin: 0; }');
lines.push('.header .time { color: #888; font-size: 14px; }');
lines.push('.section { background: #16213e; border-radius: 8px; padding: 16px; margin-bottom: 16px; }');
lines.push('.section h2 { color: #60a5fa; margin-top: 0; font-size: 18px; }');
lines.push('.stock { display: flex; justify-content: space-between; padding: 8px 0; border-bottom: 1px solid #2d3a5e; }');
lines.push('.stock:last-child { border-bottom: none; }');
lines.push('.symbol { font-weight: bold; }');
lines.push('.price { color: #4ade80; }');
lines.push('.price.down { color: #f87171; }');
lines.push('.signal { background: #1e3a5f; padding: 12px; border-radius: 8px; margin-bottom: 8px; }');
lines.push('.signal .action { font-weight: bold; text-transform: uppercase; }');
lines.push('.signal .action.buy { color: #4ade80; }');
lines.push('.signal .action.sell { color: #f87171; }');
lines.push('.recommendations { background: #16213e; border-left: 4px solid #f59e0b; padding: 16px; margin-top: 16px; }');
lines.push('</style></head><body>');
lines.push('<div class="container">');

lines.push(`<div class="header"><h1>${input.timeLabel.charAt(0).toUpperCase() + input.timeLabel.slice(1)} Report</h1>`);
lines.push(`<div class="time">${new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</div></div>`);

lines.push('<div class="section"><h2>Market Overview</h2>');
lines.push(`<p>${input.marketOverview || 'Market analysis pending.'}</p></div>`);

if (Object.keys(input.positions || {}).length > 0) {
  lines.push('<div class="section"><h2>Positions</h2>');
  for (const [id, pos] of Object.entries(input.positions)) {
    const data = stocks.find(s => s.symbol?.toLowerCase() === pos.symbol?.toLowerCase()) ||
                 crypto.find(c => c.id?.toLowerCase() === pos.symbol?.toLowerCase());
    const price = data?.current_price || 'N/A';
    const pnl = data ? ((data.current_price - pos.entry_price) / pos.entry_price * 100).toFixed(2) : 0;
    lines.push(`<div class="stock"><span class="symbol">${pos.symbol}</span>`);
    lines.push(`<span>$${pos.entry_price} -> $${price} (${pnl >= 0 ? '+' : ''}${pnl}%)</span></div>`);
  }
  lines.push('</div>');
}

lines.push('<div class="section"><h2>Top Signals</h2>');
signals.slice(0, 5).forEach(s => {
  lines.push(`<div class="signal">`);
  lines.push(`<span class="action ${s.action}">${s.symbol}: ${s.action}</span>`);
  lines.push(` <span>(${s.confidence}/100)</span>`);
  lines.push(`<br><small>${s.reason}</small>`);
  lines.push(`</div>`);
});
lines.push('</div>');

lines.push('<div class="recommendations"><h2>Recommendations</h2>');
lines.push(`<p>${input.recommendations || 'No specific recommendations.'}</p></div>`);

lines.push('</div></body></html>');

return [{
  json: {
    html: lines.join('\n'),
    subject: `Trading Report — ${input.timeLabel.charAt(0).toUpperCase() + input.timeLabel.slice(1)} Update`,
    to: 'sharingando@gmail.com',
    timeLabel: input.timeLabel,
    marketOverview: input.marketOverview,
    signals: input.signals
  }
}];

